What will the following code output after clicking the button once?

```jsx
function Counter() {
  const [count, setCount] = useState(0);
  const handleClick = () => {
    setCount(count + 1);
    setCount(count + 1);
  };
  return <button onClick={handleClick}>{count}</button>;
}
```

What will the following code render after the button is clicked?

```jsx
function Toggle() {
  const [on, setOn] = useState(false);
  const toggle = () => setOn(!on);
  return <button onClick={toggle}>{on ? 'ON' : 'OFF'}</button>;
}
```

